CREATE SCHEMA IF NOT EXISTS purchase;

CREATE OR REPLACE FUNCTION purchase._article_options()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text := '<option value="">— aucun —</option>';
  v_opts text;
  v_sql text;
  r record;
BEGIN
  -- Priority: catalog > stock > empty
  SELECT 'SELECT ' || n.nspname || '.article_options()'
    INTO v_sql
    FROM pg_namespace n
    JOIN pg_proc p ON p.pronamespace = n.oid AND p.proname = 'article_options'
   WHERE n.nspname = 'catalog';
  IF v_sql IS NOT NULL THEN
    EXECUTE v_sql INTO v_opts;
    RETURN v_html || coalesce(v_opts, '');
  END IF;

  IF EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'stock') THEN
    FOR r IN EXECUTE 'SELECT id, reference, designation FROM stock.article WHERE active = true ORDER BY reference'
    LOOP
      v_html := v_html || format('<option value="%s">%s — %s</option>', r.id, pgv.esc(r.reference), pgv.esc(r.designation));
    END LOOP;
  END IF;

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION purchase._article_options() IS 'Generate HTML option list from stock.article (dynamic, no hard dep on stock schema)';

CREATE OR REPLACE FUNCTION purchase._commande_form_body(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd purchase.commande;
  v_fournisseur_name text;
  v_body text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO v_cmd FROM purchase.commande WHERE id = p_id;
    SELECT name INTO v_fournisseur_name FROM crm.client WHERE id = v_cmd.fournisseur_id;
  END IF;

  v_body := '';
  IF p_id IS NOT NULL THEN
    v_body := format('<input type="hidden" name="p_id" value="%s">', p_id);
  END IF;

  v_body := v_body
    || pgv.select_search('p_fournisseur_id', pgv.t('purchase.field_fournisseur'),
         'fournisseur_options', pgv.t('purchase.field_search_fournisseur'),
         CASE WHEN p_id IS NOT NULL THEN v_cmd.fournisseur_id::text END,
         v_fournisseur_name)
    || pgv.input('p_objet', 'text', pgv.t('purchase.field_objet'), v_cmd.objet, true)
    || pgv.input('p_date_livraison', 'date', pgv.t('purchase.field_date_livraison'), v_cmd.date_livraison::text)
    || pgv.input('p_conditions_paiement', 'text', pgv.t('purchase.field_conditions'), v_cmd.conditions_paiement)
    || pgv.textarea('p_notes', pgv.t('purchase.field_notes'), v_cmd.notes);

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase._commande_form_body(integer) IS 'Helper: returns HTML form fields for commande creation/edition (no form wrapper)';

CREATE OR REPLACE FUNCTION purchase._fournisseur_options()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text := '<option value="">-- Choisir un fournisseur --</option>';
  r record;
BEGIN
  FOR r IN SELECT id, name FROM crm.client WHERE active ORDER BY name LOOP
    v_html := v_html || format('<option value="%s">%s</option>', r.id, pgv.esc(r.name));
  END LOOP;
  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION purchase._fournisseur_options() IS 'HTML select options for CRM clients as suppliers';

CREATE OR REPLACE FUNCTION purchase._next_number(p_prefix text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year text := to_char(now(), 'YYYY');
  v_seq int;
BEGIN
  SELECT coalesce(max(
    regexp_replace(number, '^.*-(\d+)$', '\1')::int
  ), 0) + 1
  INTO v_seq
  FROM purchase.purchase_order
  WHERE number LIKE p_prefix || '-' || v_year || '-%'
  UNION ALL
  SELECT coalesce(max(
    regexp_replace(number, '^.*-(\d+)$', '\1')::int
  ), 0) + 1
  FROM purchase.receipt
  WHERE number LIKE p_prefix || '-' || v_year || '-%'
  ORDER BY 1 DESC LIMIT 1;

  RETURN p_prefix || '-' || v_year || '-' || lpad(v_seq::text, 3, '0');
END;
$function$;
COMMENT ON FUNCTION purchase._next_number(text) IS 'Generate next sequential number (PO-2026-001, REC-2026-001)';

CREATE OR REPLACE FUNCTION purchase._remaining_quantity(p_line_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN (
    SELECT l.quantity - coalesce(sum(rl.quantity_received), 0)
    FROM purchase.order_line l
    LEFT JOIN purchase.receipt_line rl ON rl.line_id = l.id
    WHERE l.id = p_line_id
    GROUP BY l.quantity
  );
END;
$function$;
COMMENT ON FUNCTION purchase._remaining_quantity(integer) IS 'Calculate remaining quantity to receive for an order line';

CREATE OR REPLACE FUNCTION purchase._set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at := now();
  RETURN NEW;
END;
$function$;
COMMENT ON FUNCTION purchase._set_updated_at() IS 'Trigger function to auto-update updated_at timestamp';
DROP TRIGGER IF EXISTS trg_commande_updated_at ON purchase.purchase_order;
CREATE TRIGGER trg_commande_updated_at BEFORE UPDATE ON purchase.purchase_order FOR EACH ROW EXECUTE FUNCTION purchase._set_updated_at();
DROP TRIGGER IF EXISTS trg_facture_fournisseur_updated_at ON purchase.supplier_invoice;
CREATE TRIGGER trg_facture_fournisseur_updated_at BEFORE UPDATE ON purchase.supplier_invoice FOR EACH ROW EXECUTE FUNCTION purchase._set_updated_at();

CREATE OR REPLACE FUNCTION purchase._status_badge(p_status text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN CASE p_status
    WHEN 'draft' THEN pgv.badge(pgv.t('purchase.status_draft'), 'default')
    WHEN 'sent' THEN pgv.badge(pgv.t('purchase.status_sent'), 'primary')
    WHEN 'partially_received' THEN pgv.badge(pgv.t('purchase.status_partially_received'), 'warning')
    WHEN 'received' THEN pgv.badge(pgv.t('purchase.status_received'), 'success')
    WHEN 'cancelled' THEN pgv.badge(pgv.t('purchase.status_cancelled'), 'danger')
    WHEN 'validated' THEN pgv.badge(pgv.t('purchase.status_validated'), 'primary')
    WHEN 'paid' THEN pgv.badge(pgv.t('purchase.status_paid'), 'success')
    ELSE pgv.badge(p_status, 'default')
  END;
END;
$function$;
COMMENT ON FUNCTION purchase._status_badge(text) IS 'Return HTML badge for a purchase status value';

CREATE OR REPLACE FUNCTION purchase._total_ht(p_order_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN coalesce((
    SELECT sum(quantity * unit_price)
    FROM purchase.order_line
    WHERE order_id = p_order_id
  ), 0);
END;
$function$;
COMMENT ON FUNCTION purchase._total_ht(integer) IS 'Total HT for a purchase order';

CREATE OR REPLACE FUNCTION purchase._total_tva(p_order_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN coalesce((
    SELECT sum(quantity * unit_price * tva_rate / 100)
    FROM purchase.order_line
    WHERE order_id = p_order_id
  ), 0);
END;
$function$;
COMMENT ON FUNCTION purchase._total_tva(integer) IS 'Total TVA for a purchase order';

CREATE OR REPLACE FUNCTION purchase._total_ttc(p_order_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN purchase._total_ht(p_order_id) + purchase._total_tva(p_order_id);
END;
$function$;
COMMENT ON FUNCTION purchase._total_ttc(integer) IS 'Total TTC for a purchase order';

CREATE OR REPLACE FUNCTION purchase.article_options(p_search text DEFAULT ''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_result jsonb := '[]'::jsonb;
BEGIN
  -- Priority: catalog > stock
  IF EXISTS (SELECT 1 FROM pg_namespace n
             JOIN pg_proc p ON p.pronamespace = n.oid AND p.proname = 'article_options'
             WHERE n.nspname = 'catalog'
             AND pg_get_function_arguments(p.oid) LIKE '%p_search text%') THEN
    EXECUTE format('SELECT catalog.article_options(%L)', p_search) INTO v_result;
    RETURN coalesce(v_result, '[]'::jsonb);
  END IF;

  IF EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'stock') THEN
    EXECUTE format(
      'SELECT coalesce(jsonb_agg(jsonb_build_object(
         ''value'', id::text,
         ''label'', reference || '' — '' || designation,
         ''detail'', coalesce(unite, ''u'')
       )), ''[]''::jsonb)
       FROM stock.article
       WHERE active = true
         AND (%L = '''' OR reference ILIKE ''%%'' || %L || ''%%'' OR designation ILIKE ''%%'' || %L || ''%%'')
       ORDER BY reference
       LIMIT 30',
      p_search, p_search, p_search
    ) INTO v_result;
  END IF;

  RETURN coalesce(v_result, '[]'::jsonb);
END;
$function$;
COMMENT ON FUNCTION purchase.article_options(text) IS 'Search-select RPC: returns jsonb array of stock articles matching search term';

CREATE OR REPLACE FUNCTION purchase.brand()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN pgv.t('purchase.brand');
END;
$function$;
COMMENT ON FUNCTION purchase.brand() IS 'Brand name for purchase module';

CREATE OR REPLACE FUNCTION purchase.fournisseur_options(p_search text DEFAULT ''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_result jsonb;
BEGIN
  SELECT coalesce(jsonb_agg(row_j ORDER BY row_j->>'label'), '[]'::jsonb)
  INTO v_result
  FROM (
    SELECT jsonb_build_object(
      'value', id::text,
      'label', name,
      'detail', coalesce(email, phone, '')
    ) AS row_j
    FROM crm.client
    WHERE active
      AND (p_search = '' OR name ILIKE '%' || p_search || '%' OR email ILIKE '%' || p_search || '%')
    LIMIT 30
  ) sub;

  RETURN coalesce(v_result, '[]'::jsonb);
END;
$function$;
COMMENT ON FUNCTION purchase.fournisseur_options(text) IS 'Search-select RPC: returns jsonb array of CRM clients matching search term';

CREATE OR REPLACE FUNCTION purchase.get_article_prix(p_article_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_ref text;
  v_designation text;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  -- Retrieve article info (priority: catalog > stock)
  IF EXISTS (SELECT 1 FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
             WHERE n.nspname = 'catalog' AND c.relname = 'article') THEN
    EXECUTE format('SELECT reference, designation FROM catalog.article WHERE id = %L', p_article_id)
      INTO v_ref, v_designation;
  ELSIF EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'stock') THEN
    EXECUTE format('SELECT reference, designation FROM stock.article WHERE id = %L', p_article_id)
      INTO v_ref, v_designation;
  END IF;

  IF v_ref IS NULL THEN
    v_ref := '#' || p_article_id;
    v_designation := 'Article ' || p_article_id;
  END IF;

  v_body := '<h3>' || pgv.t('purchase.title_historique_prix') || ' — ' || pgv.esc(v_ref) || ' ' || pgv.esc(v_designation) || '</h3>';

  -- Price history: all purchase lines with this article_id, grouped by supplier
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT cl.name AS fournisseur, c.numero, l.prix_unitaire, l.unite,
           l.quantite, c.created_at,
           purchase._statut_badge(c.statut) AS badge
      FROM purchase.ligne l
      JOIN purchase.commande c ON c.id = l.commande_id
      JOIN crm.client cl ON cl.id = c.fournisseur_id
     WHERE l.article_id = p_article_id
     ORDER BY c.created_at DESC
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.fournisseur),
      pgv.esc(r.numero),
      to_char(r.prix_unitaire, 'FM999 990.00') || ' EUR/' || r.unite,
      r.quantite::text || ' ' || r.unite,
      r.badge,
      to_char(r.created_at, 'DD/MM/YYYY')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty(pgv.t('purchase.empty_no_achat_article'));
  ELSE
    -- Stats summary
    v_body := v_body || pgv.grid(VARIADIC ARRAY[
      pgv.stat(pgv.t('purchase.stat_achats'), (array_length(v_rows, 1) / 6)::text),
      pgv.stat(pgv.t('purchase.stat_prix_min'), (SELECT to_char(min(l.prix_unitaire), 'FM999 990.00') || ' EUR'
        FROM purchase.ligne l WHERE l.article_id = p_article_id)),
      pgv.stat(pgv.t('purchase.stat_prix_max'), (SELECT to_char(max(l.prix_unitaire), 'FM999 990.00') || ' EUR'
        FROM purchase.ligne l WHERE l.article_id = p_article_id)),
      pgv.stat(pgv.t('purchase.stat_prix_moyen'), (SELECT to_char(avg(l.prix_unitaire), 'FM999 990.00') || ' EUR'
        FROM purchase.ligne l WHERE l.article_id = p_article_id))
    ]);
    v_body := v_body || pgv.md_table(
      ARRAY[pgv.t('purchase.col_fournisseur'), pgv.t('purchase.col_commande'), pgv.t('purchase.col_prix_unitaire'), pgv.t('purchase.col_quantite'), pgv.t('purchase.col_statut'), pgv.t('purchase.col_date')],
      v_rows);
  END IF;

  -- Link to catalog if available
  IF EXISTS (SELECT 1 FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
             WHERE n.nspname = 'catalog' AND c.relname = 'article') THEN
    v_body := v_body || format('<p><a href="/catalog/article?p_id=%s">%s</a> | ', p_article_id, pgv.t('purchase.btn_voir_fiche'));
  ELSE
    v_body := v_body || '<p>';
  END IF;
  v_body := v_body || format('<a href="%s">%s</a></p>', pgv.call_ref('get_commande'), pgv.t('purchase.btn_retour_commandes'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_article_prix(integer) IS 'Historique des prix d achat d un article par fournisseur';

CREATE OR REPLACE FUNCTION purchase.get_bon_commande(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd purchase.commande;
  v_fournisseur record;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  SELECT * INTO v_cmd FROM purchase.commande WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty(pgv.t('purchase.empty_commande_introuvable')); END IF;

  -- Fournisseur details
  SELECT cl.name, cl.email, cl.phone, cl.address, cl.city
    INTO v_fournisseur
    FROM crm.client cl WHERE cl.id = v_cmd.fournisseur_id;

  -- Header
  v_body := '<div class="pgv-print">';
  v_body := v_body || '<h2>' || pgv.t('purchase.title_bon_commande') || ' ' || pgv.esc(v_cmd.numero) || '</h2>';

  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.card(pgv.t('purchase.card_fournisseur'),
      pgv.esc(v_fournisseur.name)
      || coalesce('<br>' || pgv.esc(v_fournisseur.address), '')
      || coalesce('<br>' || pgv.esc(v_fournisseur.city), '')
      || coalesce('<br>' || pgv.esc(v_fournisseur.email), '')
      || coalesce('<br>' || pgv.esc(v_fournisseur.phone), '')
    ),
    pgv.card(pgv.t('purchase.card_commande'),
      '<strong>' || pgv.t('purchase.label_no') || '</strong> ' || pgv.esc(v_cmd.numero)
      || '<br><strong>' || pgv.t('purchase.label_date') || '</strong> ' || to_char(v_cmd.created_at, 'DD/MM/YYYY')
      || '<br><strong>' || pgv.t('purchase.label_objet') || '</strong> ' || pgv.esc(v_cmd.objet)
      || CASE WHEN v_cmd.date_livraison IS NOT NULL
         THEN '<br><strong>' || pgv.t('purchase.label_livraison_souhaitee') || '</strong> ' || to_char(v_cmd.date_livraison, 'DD/MM/YYYY')
         ELSE '' END
      || CASE WHEN v_cmd.conditions_paiement <> ''
         THEN '<br><strong>' || pgv.t('purchase.label_paiement') || '</strong> ' || pgv.esc(v_cmd.conditions_paiement)
         ELSE '' END
    )
  ]);

  -- Lines table
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT l.description, l.quantite, l.unite, l.prix_unitaire, l.tva_rate,
           round(l.quantite * l.prix_unitaire, 2) AS total_ht
      FROM purchase.ligne l
     WHERE l.commande_id = p_id
     ORDER BY l.sort_order
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.description),
      r.quantite::text,
      r.unite,
      to_char(r.prix_unitaire, 'FM999 990.00'),
      r.tva_rate::text || '%',
      to_char(r.total_ht, 'FM999 990.00')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || pgv.md_table(
      ARRAY[pgv.t('purchase.col_designation'), pgv.t('purchase.col_qte'), pgv.t('purchase.col_unite'), pgv.t('purchase.col_pu_ht'), pgv.t('purchase.col_tva'), pgv.t('purchase.col_total_ht')],
      v_rows);
  END IF;

  -- Totals
  v_body := v_body || '<p>'
    || '<strong>' || pgv.t('purchase.label_total_ht') || '</strong> ' || to_char(purchase._total_ht(p_id), 'FM999 990.00') || ' EUR'
    || ' | <strong>' || pgv.t('purchase.label_tva') || '</strong> ' || to_char(purchase._total_tva(p_id), 'FM999 990.00') || ' EUR'
    || ' | <strong>' || pgv.t('purchase.label_total_ttc') || '</strong> ' || to_char(purchase._total_ttc(p_id), 'FM999 990.00') || ' EUR'
    || '</p>';

  IF v_cmd.notes <> '' THEN
    v_body := v_body || '<p><strong>' || pgv.t('purchase.label_notes') || '</strong> ' || pgv.esc(v_cmd.notes) || '</p>';
  END IF;

  v_body := v_body || '</div>';

  -- Back link (hidden in print)
  v_body := v_body || format('<p><a href="%s">%s</a></p>',
    pgv.call_ref('get_commande', jsonb_build_object('p_id', p_id)), pgv.t('purchase.btn_retour_commande'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_bon_commande(integer) IS 'Vue imprimable/PDF-ready d un bon de commande fournisseur';

CREATE OR REPLACE FUNCTION purchase.get_commande(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd purchase.commande;
  v_fournisseur text;
  v_body text;
  v_rows text[];
  v_rows_r text[];
  r record;
BEGIN
  -- Liste si pas d'id
  IF p_id IS NULL THEN
    v_rows := ARRAY[]::text[];
    FOR r IN
      SELECT c.id, c.fournisseur_id, c.numero, cl.name AS fournisseur, c.objet, c.statut,
             purchase._total_ttc(c.id) AS ttc, c.created_at
        FROM purchase.commande c
        JOIN crm.client cl ON cl.id = c.fournisseur_id
       ORDER BY c.created_at DESC
    LOOP
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_commande', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
        format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur)),
        pgv.esc(r.objet),
        purchase._statut_badge(r.statut)
          || CASE WHEN r.statut IN ('envoyee', 'partiellement_recue')
                      AND r.created_at < now() - interval '14 days'
             THEN ' ' || pgv.badge(pgv.t('purchase.badge_retard'), 'danger')
             ELSE '' END,
        to_char(r.ttc, 'FM999 990.00') || ' EUR',
        to_char(r.created_at, 'DD/MM/YYYY')
      ];
    END LOOP;

    IF array_length(v_rows, 1) IS NULL THEN
      RETURN pgv.empty(pgv.t('purchase.empty_no_commande'), pgv.t('purchase.empty_first_commande'))
        || '<p>' || pgv.form_dialog('dlg-new-commande', pgv.t('purchase.title_nouvelle_commande'),
             purchase._commande_form_body(),
             'post_commande_save', pgv.t('purchase.btn_nouvelle_commande')) || '</p>';
    END IF;

    RETURN '<p>' || pgv.form_dialog('dlg-new-commande', pgv.t('purchase.title_nouvelle_commande'),
         purchase._commande_form_body(),
         'post_commande_save', pgv.t('purchase.btn_nouvelle_commande')) || '</p>'
      || pgv.md_table(ARRAY[pgv.t('purchase.col_numero'), pgv.t('purchase.col_fournisseur'), pgv.t('purchase.col_objet'), pgv.t('purchase.col_statut'), pgv.t('purchase.col_total_ttc'), pgv.t('purchase.col_date')], v_rows);
  END IF;

  -- Détail
  SELECT * INTO v_cmd FROM purchase.commande WHERE id = p_id;
  SELECT name INTO v_fournisseur FROM crm.client WHERE id = v_cmd.fournisseur_id;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.card(pgv.t('purchase.card_commande'), v_cmd.numero || '<br>' || purchase._statut_badge(v_cmd.statut)),
    pgv.card(pgv.t('purchase.card_fournisseur'), format('<a href="/crm/client?p_id=%s">%s</a>', v_cmd.fournisseur_id, pgv.esc(v_fournisseur))),
    pgv.card(pgv.t('purchase.card_total_ttc'), to_char(purchase._total_ttc(p_id), 'FM999 990.00') || ' EUR'),
    pgv.card(pgv.t('purchase.card_livraison'), coalesce(to_char(v_cmd.date_livraison, 'DD/MM/YYYY'), '—'))
  ]);

  -- Workflow progression
  IF v_cmd.statut <> 'annulee' THEN
    v_body := v_body || pgv.workflow(
      jsonb_build_array(
        jsonb_build_object('key', 'brouillon', 'label', pgv.t('purchase.wf_brouillon')),
        jsonb_build_object('key', 'envoyee', 'label', pgv.t('purchase.wf_envoyee')),
        jsonb_build_object('key', 'partiellement_recue', 'label', pgv.t('purchase.wf_partielle')),
        jsonb_build_object('key', 'recue', 'label', pgv.t('purchase.wf_recue'))
      ),
      v_cmd.statut);
  END IF;

  IF v_cmd.objet <> '' THEN
    v_body := v_body || '<p><strong>' || pgv.t('purchase.label_objet') || '</strong> ' || pgv.esc(v_cmd.objet) || '</p>';
  END IF;
  IF v_cmd.conditions_paiement <> '' THEN
    v_body := v_body || '<p><strong>' || pgv.t('purchase.label_conditions') || '</strong> ' || pgv.esc(v_cmd.conditions_paiement) || '</p>';
  END IF;
  IF v_cmd.notes <> '' THEN
    v_body := v_body || '<p><strong>' || pgv.t('purchase.label_notes') || '</strong> ' || pgv.esc(v_cmd.notes) || '</p>';
  END IF;

  -- Lignes
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT l.id, l.description, l.quantite, l.unite, l.prix_unitaire, l.tva_rate,
           (l.quantite * l.prix_unitaire) AS total_ht,
           purchase._quantite_restante(l.id) AS restante,
           l.article_id
      FROM purchase.ligne l
     WHERE l.commande_id = p_id
     ORDER BY l.sort_order
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.description) || CASE WHEN r.article_id IS NOT NULL
        THEN ' ' || format('<a href="%s">', pgv.call_ref('get_article_prix', jsonb_build_object('p_article_id', r.article_id)))
          || pgv.badge('art. #' || r.article_id, 'info') || '</a>'
        ELSE '' END,
      r.quantite::text || ' ' || r.unite,
      to_char(r.prix_unitaire, 'FM999 990.00') || ' EUR',
      r.tva_rate::text || '%',
      to_char(r.total_ht, 'FM999 990.00') || ' EUR',
      CASE WHEN v_cmd.statut IN ('envoyee', 'partiellement_recue')
        THEN r.restante::text || ' ' || r.unite
        ELSE '—'
      END,
      CASE WHEN v_cmd.statut = 'brouillon'
        THEN pgv.action('post_ligne_supprimer', pgv.t('purchase.btn_supprimer'),
               jsonb_build_object('p_ligne_id', r.id),
               pgv.t('purchase.confirm_supprimer_ligne'), 'danger')
        ELSE ''
      END
    ];
  END LOOP;

  v_body := v_body || '<h4>' || pgv.t('purchase.title_lignes') || '</h4>';
  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty(pgv.t('purchase.empty_no_ligne'));
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY[pgv.t('purchase.col_description'), pgv.t('purchase.col_qte'), pgv.t('purchase.col_pu'), pgv.t('purchase.col_tva'), pgv.t('purchase.col_total_ht'), pgv.t('purchase.col_restant'), ''],
      v_rows);
    v_body := v_body || '<p><strong>' || pgv.t('purchase.label_total_ht') || '</strong> ' || to_char(purchase._total_ht(p_id), 'FM999 990.00') || ' EUR'
      || ' | <strong>' || pgv.t('purchase.label_tva') || '</strong> ' || to_char(purchase._total_tva(p_id), 'FM999 990.00') || ' EUR'
      || ' | <strong>' || pgv.t('purchase.label_ttc') || '</strong> ' || to_char(purchase._total_ttc(p_id), 'FM999 990.00') || ' EUR</p>';
  END IF;

  -- Formulaire ajout ligne (brouillon)
  IF v_cmd.statut = 'brouillon' THEN
    DECLARE v_add_body text;
    BEGIN
      v_add_body := format('<input type="hidden" name="p_commande_id" value="%s">', p_id)
        || pgv.input('p_description', 'text', pgv.t('purchase.field_description'), NULL, true)
        || '<div class="pgv-grid">'
        || '<label>' || pgv.t('purchase.field_quantite') || '<input type="number" name="p_quantite" value="1" step="0.01" min="0.01"></label>'
        || pgv.sel('p_unite', pgv.t('purchase.field_unite'),
             '[{"value":"u","label":"u"},{"value":"h","label":"h"},{"value":"m","label":"m"},{"value":"m2","label":"m\u00b2"},{"value":"m3","label":"m\u00b3"},{"value":"kg","label":"kg"},{"value":"forfait","label":"forfait"}]'::jsonb, 'u')
        || '<label>' || pgv.t('purchase.field_prix_unitaire') || '<input type="number" name="p_prix_unitaire" step="0.01" min="0" required></label>'
        || pgv.sel('p_tva_rate', pgv.t('purchase.field_tva'),
             '[{"value":"20.00","label":"20%"},{"value":"10.00","label":"10%"},{"value":"5.50","label":"5.5%"},{"value":"0.00","label":"0%"}]'::jsonb, '20.00')
        || '</div>'
        || pgv.select_search('p_article_id', pgv.t('purchase.field_article_stock'), 'article_options', pgv.t('purchase.field_search_article'));
      v_body := v_body || pgv.form_dialog('dlg-add-ligne', pgv.t('purchase.btn_ajouter_ligne'),
        v_add_body,
        'post_ligne_ajouter', pgv.t('purchase.btn_ajouter'));
    END;
  END IF;

  -- Réceptions
  v_rows_r := ARRAY[]::text[];
  FOR r IN
    SELECT rc.id, rc.numero, rc.received_at, rc.notes,
           (SELECT count(*) FROM purchase.reception_ligne rl WHERE rl.reception_id = rc.id) AS nb_lignes
      FROM purchase.reception rc
     WHERE rc.commande_id = p_id
     ORDER BY rc.received_at DESC
  LOOP
    v_rows_r := v_rows_r || ARRAY[
      pgv.esc(r.numero),
      to_char(r.received_at, 'DD/MM/YYYY HH24:MI'),
      r.nb_lignes::text || ' ' || pgv.t('purchase.col_lignes'),
      coalesce(pgv.esc(r.notes), '')
    ];
  END LOOP;

  IF array_length(v_rows_r, 1) IS NOT NULL THEN
    v_body := v_body || '<h4>' || pgv.t('purchase.title_receptions') || '</h4>'
      || pgv.md_table(ARRAY[pgv.t('purchase.col_numero'), pgv.t('purchase.col_date'), pgv.t('purchase.col_lignes'), pgv.t('purchase.col_notes')], v_rows_r);
  END IF;

  -- Bon de commande link
  v_body := v_body || format('<p><a href="%s">%s</a></p>',
    pgv.call_ref('get_bon_commande', jsonb_build_object('p_id', p_id)), pgv.t('purchase.btn_voir_bon'));

  -- Actions
  v_body := v_body || '<p>';
  IF v_cmd.statut = 'brouillon' THEN
    v_body := v_body
      || pgv.form_dialog('dlg-edit-commande', pgv.t('purchase.title_modifier_commande') || ' ' || v_cmd.numero,
           purchase._commande_form_body(p_id),
           'post_commande_save', pgv.t('purchase.btn_modifier'), 'outline') || ' '
      || pgv.action('post_commande_envoyer', pgv.t('purchase.btn_envoyer'),
           jsonb_build_object('p_id', p_id),
           pgv.t('purchase.confirm_envoyer')) || ' '
      || pgv.action('post_commande_annuler', pgv.t('purchase.btn_annuler'),
           jsonb_build_object('p_id', p_id),
           pgv.t('purchase.confirm_annuler'), 'danger');
  ELSIF v_cmd.statut IN ('envoyee', 'partiellement_recue') THEN
    v_body := v_body
      || pgv.action('post_reception_creer', pgv.t('purchase.btn_receptionner'),
           jsonb_build_object('p_commande_id', p_id),
           pgv.t('purchase.confirm_reception')) || ' '
      || pgv.action('post_commande_annuler', pgv.t('purchase.btn_annuler'),
           jsonb_build_object('p_id', p_id),
           pgv.t('purchase.confirm_annuler'), 'danger');
  END IF;
  v_body := v_body || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_commande(integer) IS 'Purchase order detail with lines, receptions, and actions by status';

CREATE OR REPLACE FUNCTION purchase.get_commande_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_title text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT pgv.t('purchase.title_modifier_commande') || ' ' || numero
      INTO v_title
      FROM purchase.commande WHERE id = p_id;
  ELSE
    v_title := pgv.t('purchase.title_nouvelle_commande');
  END IF;

  RETURN '<h3>' || pgv.esc(v_title) || '</h3>'
    || pgv.form('post_commande_save', purchase._commande_form_body(p_id), pgv.t('purchase.btn_enregistrer'));
END;
$function$;
COMMENT ON FUNCTION purchase.get_commande_form(integer) IS 'Form to create or edit a purchase order (standalone page, uses _commande_form_body helper)';

CREATE OR REPLACE FUNCTION purchase.get_facture_fournisseur(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_fac purchase.facture_fournisseur;
  v_cmd_numero text;
  v_fournisseur_id int;
  v_fournisseur_name text;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  -- Liste si pas d'id
  IF p_id IS NULL THEN
    v_rows := ARRAY[]::text[];
    FOR r IN
      SELECT f.id, f.numero_fournisseur, c.numero AS cmd_numero,
             cl.id AS fournisseur_id, cl.name AS fournisseur,
             f.montant_ttc, f.statut, f.date_facture, f.date_echeance
        FROM purchase.facture_fournisseur f
        LEFT JOIN purchase.commande c ON c.id = f.commande_id
        LEFT JOIN crm.client cl ON cl.id = c.fournisseur_id
       ORDER BY f.created_at DESC
    LOOP
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_facture_fournisseur', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero_fournisseur)),
        coalesce(format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur)), '—'),
        coalesce(r.cmd_numero, '—'),
        purchase._statut_badge(r.statut),
        to_char(r.montant_ttc, 'FM999 990.00') || ' EUR',
        to_char(r.date_facture, 'DD/MM/YYYY'),
        coalesce(to_char(r.date_echeance, 'DD/MM/YYYY'), '—')
      ];
    END LOOP;

    IF array_length(v_rows, 1) IS NULL THEN
      RETURN pgv.empty(pgv.t('purchase.empty_no_facture'), pgv.t('purchase.empty_facture_hint'));
    END IF;

    DECLARE
      v_form_body text;
      v_cmd_options jsonb;
    BEGIN
      SELECT coalesce(jsonb_agg(jsonb_build_object('value', id::text, 'label', numero)), '[]'::jsonb)
        INTO v_cmd_options
        FROM (SELECT id, numero FROM purchase.commande ORDER BY created_at DESC LIMIT 20) sub;

      v_form_body := pgv.input('p_numero_fournisseur', 'text', pgv.t('purchase.field_no_fournisseur'), NULL, true)
        || '<div class="pgv-grid">'
        || '<label>' || pgv.t('purchase.field_montant_ht') || '<input type="number" name="p_montant_ht" step="0.01" min="0" required></label>'
        || '<label>' || pgv.t('purchase.field_montant_ttc') || '<input type="number" name="p_montant_ttc" step="0.01" min="0" required></label>'
        || '</div>'
        || '<div class="pgv-grid">'
        || pgv.input('p_date_facture', 'date', pgv.t('purchase.field_date_facture'), NULL, true)
        || pgv.input('p_date_echeance', 'date', pgv.t('purchase.field_date_echeance'))
        || '</div>'
        || pgv.sel('p_commande_id', pgv.t('purchase.field_commande_liee'), v_cmd_options)
        || pgv.textarea('p_notes', pgv.t('purchase.field_notes'));

      RETURN pgv.form_dialog('dlg-saisir-facture', pgv.t('purchase.title_saisir_facture'),
        v_form_body,
        'post_facture_saisir', pgv.t('purchase.btn_saisir'))
      || pgv.md_table(ARRAY[pgv.t('purchase.col_no_fournisseur'), pgv.t('purchase.col_fournisseur'), pgv.t('purchase.col_commande'), pgv.t('purchase.col_statut'), pgv.t('purchase.col_montant_ttc'), pgv.t('purchase.col_date_facture'), pgv.t('purchase.col_echeance')], v_rows);
    END;
  END IF;

  -- Détail
  SELECT * INTO v_fac FROM purchase.facture_fournisseur WHERE id = p_id;
  SELECT numero INTO v_cmd_numero FROM purchase.commande WHERE id = v_fac.commande_id;

  -- Fournisseur via commande
  SELECT c.fournisseur_id, cl.name INTO v_fournisseur_id, v_fournisseur_name
    FROM purchase.commande c
    JOIN crm.client cl ON cl.id = c.fournisseur_id
   WHERE c.id = v_fac.commande_id;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.card(pgv.t('purchase.card_facture'), pgv.esc(v_fac.numero_fournisseur) || '<br>' || purchase._statut_badge(v_fac.statut)),
    pgv.card(pgv.t('purchase.card_fournisseur'), CASE WHEN v_fournisseur_id IS NOT NULL
      THEN format('<a href="/crm/client?p_id=%s">%s</a>', v_fournisseur_id, pgv.esc(v_fournisseur_name))
      ELSE '—' END),
    pgv.card(pgv.t('purchase.card_commande'), coalesce(v_cmd_numero, '—')),
    pgv.card(pgv.t('purchase.card_montant_ht'), to_char(v_fac.montant_ht, 'FM999 990.00') || ' EUR'),
    pgv.card(pgv.t('purchase.card_montant_ttc'), to_char(v_fac.montant_ttc, 'FM999 990.00') || ' EUR')
  ]);

  -- Workflow progression
  v_body := v_body || pgv.workflow(
    jsonb_build_array(
      jsonb_build_object('key', 'recue', 'label', pgv.t('purchase.wf_recue_fac')),
      jsonb_build_object('key', 'validee', 'label', pgv.t('purchase.wf_validee')),
      jsonb_build_object('key', 'payee', 'label', pgv.t('purchase.wf_payee'))
    ),
    v_fac.statut);

  v_body := v_body || '<p>'
    || '<strong>' || pgv.t('purchase.label_date_facture') || '</strong> ' || to_char(v_fac.date_facture, 'DD/MM/YYYY')
    || ' | <strong>' || pgv.t('purchase.label_echeance') || '</strong> ' || coalesce(to_char(v_fac.date_echeance, 'DD/MM/YYYY'), '—')
    || '</p>';

  IF v_fac.notes <> '' THEN
    v_body := v_body || '<p><strong>' || pgv.t('purchase.label_notes') || '</strong> ' || pgv.esc(v_fac.notes) || '</p>';
  END IF;

  -- Rapprochement: comparer montants commande vs facture
  IF v_fac.commande_id IS NOT NULL THEN
    DECLARE
      v_cmd_ttc numeric;
      v_ecart numeric;
    BEGIN
      v_cmd_ttc := purchase._total_ttc(v_fac.commande_id);
      v_ecart := v_fac.montant_ttc - v_cmd_ttc;
      v_body := v_body || '<p><strong>' || pgv.t('purchase.label_rapprochement') || '</strong> ' || pgv.t('purchase.label_commande_ttc') || ' '
        || to_char(v_cmd_ttc, 'FM999 990.00') || ' EUR'
        || ' | ' || pgv.t('purchase.label_ecart') || ' ' || to_char(v_ecart, 'FM999 990.00') || ' EUR';
      IF abs(v_ecart) > 0.01 THEN
        v_body := v_body || ' ' || pgv.badge(pgv.t('purchase.badge_ecart'), 'warning');
      ELSE
        v_body := v_body || ' ' || pgv.badge(pgv.t('purchase.badge_ok'), 'success');
      END IF;
      v_body := v_body || '</p>';
    END;
  END IF;

  -- Actions
  v_body := v_body || '<p>';
  IF v_fac.statut = 'recue' THEN
    v_body := v_body || pgv.action('post_facture_valider', pgv.t('purchase.btn_valider'),
      jsonb_build_object('p_id', p_id),
      pgv.t('purchase.confirm_valider_facture'));
  ELSIF v_fac.statut = 'validee' THEN
    v_body := v_body || pgv.action('post_facture_payer', pgv.t('purchase.btn_payer'),
      jsonb_build_object('p_id', p_id),
      pgv.t('purchase.confirm_payer'));
  ELSIF v_fac.statut = 'payee' AND NOT v_fac.comptabilisee THEN
    v_body := v_body || pgv.action('post_facture_comptabiliser', pgv.t('purchase.btn_comptabiliser'),
      jsonb_build_object('p_id', p_id),
      pgv.t('purchase.confirm_comptabiliser'));
  END IF;
  IF v_fac.comptabilisee THEN
    v_body := v_body || ' ' || pgv.badge(pgv.t('purchase.badge_comptabilisee'), 'success');
  END IF;
  v_body := v_body || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_facture_fournisseur(integer) IS 'Supplier invoice list or detail with reconciliation and CRM links';

CREATE OR REPLACE FUNCTION purchase.get_index()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd_en_cours int;
  v_receptions_attente int;
  v_factures_impayees int;
  v_achats_mois numeric(12,2);
  v_total_a_payer numeric(12,2);
  v_body text;
  v_rows_c text[];
  v_rows_f text[];
  v_rows_s text[];
  v_en_retard int;
  r record;
BEGIN
  -- KPIs
  SELECT count(*)::int INTO v_cmd_en_cours
    FROM purchase.commande WHERE statut IN ('envoyee', 'partiellement_recue');

  SELECT count(DISTINCT c.id)::int INTO v_receptions_attente
    FROM purchase.commande c
    JOIN purchase.ligne l ON l.commande_id = c.id
   WHERE c.statut IN ('envoyee', 'partiellement_recue')
     AND purchase._quantite_restante(l.id) > 0;

  SELECT count(*)::int INTO v_factures_impayees
    FROM purchase.facture_fournisseur WHERE statut IN ('recue', 'validee');

  SELECT coalesce(sum(montant_ttc), 0) INTO v_achats_mois
    FROM purchase.facture_fournisseur
   WHERE statut = 'payee'
     AND created_at >= date_trunc('month', now());

  SELECT coalesce(sum(montant_ttc), 0) INTO v_total_a_payer
    FROM purchase.facture_fournisseur WHERE statut IN ('recue', 'validee');

  SELECT count(*)::int INTO v_en_retard
    FROM purchase.commande
   WHERE statut IN ('envoyee', 'partiellement_recue')
     AND created_at < now() - interval '14 days';

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('purchase.stat_commandes_en_cours'), v_cmd_en_cours::text),
    pgv.stat(pgv.t('purchase.stat_a_receptionner'), v_receptions_attente::text),
    pgv.stat(pgv.t('purchase.stat_factures_impayees'), v_factures_impayees::text),
    pgv.stat(pgv.t('purchase.stat_achats_mois'), to_char(v_achats_mois, 'FM999 990.00') || ' EUR'),
    pgv.stat(pgv.t('purchase.stat_total_a_payer'), to_char(v_total_a_payer, 'FM999 990.00') || ' EUR'),
    CASE WHEN v_en_retard > 0
      THEN pgv.stat(pgv.t('purchase.stat_en_retard'), v_en_retard::text || ' ' || pgv.badge(pgv.t('purchase.badge_14j'), 'danger'))
      ELSE pgv.stat(pgv.t('purchase.stat_en_retard'), '0')
    END
  ]);

  -- Tab: Commandes récentes
  v_rows_c := ARRAY[]::text[];
  FOR r IN
    SELECT c.id, c.fournisseur_id, c.numero, cl.name AS fournisseur, c.objet, c.statut,
           purchase._total_ttc(c.id) AS ttc, c.created_at
      FROM purchase.commande c
      JOIN crm.client cl ON cl.id = c.fournisseur_id
     ORDER BY c.created_at DESC LIMIT 10
  LOOP
    v_rows_c := v_rows_c || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_commande', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
      format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur)),
      pgv.esc(r.objet),
      purchase._statut_badge(r.statut)
        || CASE WHEN r.statut IN ('envoyee', 'partiellement_recue')
                    AND r.created_at < now() - interval '14 days'
           THEN ' ' || pgv.badge(pgv.t('purchase.badge_retard'), 'danger')
           ELSE '' END,
      to_char(r.ttc, 'FM999 990.00') || ' EUR',
      to_char(r.created_at, 'DD/MM/YYYY')
    ];
  END LOOP;

  -- Tab: Factures récentes
  v_rows_f := ARRAY[]::text[];
  FOR r IN
    SELECT f.id, f.numero_fournisseur, c.numero AS cmd_numero,
           f.montant_ttc, f.statut, f.date_facture, f.date_echeance
      FROM purchase.facture_fournisseur f
      LEFT JOIN purchase.commande c ON c.id = f.commande_id
     ORDER BY f.created_at DESC LIMIT 10
  LOOP
    v_rows_f := v_rows_f || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_facture_fournisseur', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero_fournisseur)),
      coalesce(r.cmd_numero, '—'),
      purchase._statut_badge(r.statut),
      to_char(r.montant_ttc, 'FM999 990.00') || ' EUR',
      to_char(r.date_facture, 'DD/MM/YYYY'),
      coalesce(to_char(r.date_echeance, 'DD/MM/YYYY'), '—')
    ];
  END LOOP;

  -- Tab: Top fournisseurs
  v_rows_s := ARRAY[]::text[];
  FOR r IN
    SELECT cl.id AS fournisseur_id, cl.name AS fournisseur,
           count(c.id)::int AS nb_cmd,
           coalesce(sum(purchase._total_ht(c.id)), 0) AS total_ht,
           max(c.created_at) AS last_cmd
      FROM purchase.commande c
      JOIN crm.client cl ON cl.id = c.fournisseur_id
     GROUP BY cl.id, cl.name
     ORDER BY total_ht DESC
     LIMIT 10
  LOOP
    v_rows_s := v_rows_s || ARRAY[
      format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur)),
      r.nb_cmd::text,
      to_char(r.total_ht, 'FM999 990.00') || ' EUR',
      to_char(r.last_cmd, 'DD/MM/YYYY')
    ];
  END LOOP;

  v_body := v_body || pgv.tabs(VARIADIC ARRAY[
    pgv.t('purchase.tab_commandes_recentes'),
    CASE WHEN array_length(v_rows_c, 1) IS NULL
      THEN pgv.empty(pgv.t('purchase.empty_no_commande'), pgv.t('purchase.empty_first_commande'))
      ELSE pgv.md_table(ARRAY[pgv.t('purchase.col_numero'), pgv.t('purchase.col_fournisseur'), pgv.t('purchase.col_objet'), pgv.t('purchase.col_statut'), pgv.t('purchase.col_total_ttc'), pgv.t('purchase.col_date')], v_rows_c)
    END,
    pgv.t('purchase.tab_factures_fournisseur'),
    CASE WHEN array_length(v_rows_f, 1) IS NULL
      THEN pgv.empty(pgv.t('purchase.empty_no_facture'))
      ELSE pgv.md_table(ARRAY[pgv.t('purchase.col_no_fournisseur'), pgv.t('purchase.col_commande'), pgv.t('purchase.col_statut'), pgv.t('purchase.col_montant_ttc'), pgv.t('purchase.col_date_facture'), pgv.t('purchase.col_echeance')], v_rows_f)
    END,
    pgv.t('purchase.tab_top_fournisseurs'),
    CASE WHEN array_length(v_rows_s, 1) IS NULL
      THEN pgv.empty(pgv.t('purchase.empty_no_commande'))
      ELSE pgv.md_table(ARRAY[pgv.t('purchase.col_fournisseur'), pgv.t('purchase.col_commandes'), pgv.t('purchase.col_total_achats_ht'), pgv.t('purchase.col_derniere_commande')], v_rows_s)
    END
  ]);

  v_body := v_body || '<p>'
    || pgv.form_dialog('dlg-new-commande', pgv.t('purchase.title_nouvelle_commande'),
         purchase._commande_form_body(),
         'post_commande_save', pgv.t('purchase.btn_nouvelle_commande'))
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_index() IS 'Dashboard purchase: KPI stats + tabs commandes/factures récentes';

CREATE OR REPLACE FUNCTION purchase.get_recapitulatif(p_annee integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_annee int := coalesce(p_annee, extract(year FROM now())::int);
  v_body text;
  v_headers text[];
  v_rows text[];
  r record;
  v_total_annuel numeric(12,2) := 0;
BEGIN
  v_headers := ARRAY[
    pgv.t('purchase.col_fournisseur'),
    pgv.t('purchase.month_jan'), pgv.t('purchase.month_feb'), pgv.t('purchase.month_mar'),
    pgv.t('purchase.month_apr'), pgv.t('purchase.month_may'), pgv.t('purchase.month_jun'),
    pgv.t('purchase.month_jul'), pgv.t('purchase.month_aug'), pgv.t('purchase.month_sep'),
    pgv.t('purchase.month_oct'), pgv.t('purchase.month_nov'), pgv.t('purchase.month_dec'),
    pgv.t('purchase.col_total')
  ];

  v_body := '<h3>' || pgv.t('purchase.title_recap') || ' ' || v_annee || '</h3>';

  -- Year navigation
  v_body := v_body || '<div role="group">'
    || format('<a href="%s" role="button" class="outline secondary">&laquo; %s</a>',
       pgv.call_ref('get_recapitulatif', jsonb_build_object('p_annee', v_annee - 1)), v_annee - 1)
    || '<a role="button">' || v_annee || '</a>'
    || format('<a href="%s" role="button" class="outline secondary">%s &raquo;</a>',
       pgv.call_ref('get_recapitulatif', jsonb_build_object('p_annee', v_annee + 1)), v_annee + 1)
    || '</div>';

  -- Build rows per supplier
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT cl.id AS fournisseur_id, cl.name AS fournisseur,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 1) AS m01,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 2) AS m02,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 3) AS m03,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 4) AS m04,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 5) AS m05,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 6) AS m06,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 7) AS m07,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 8) AS m08,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 9) AS m09,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 10) AS m10,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 11) AS m11,
           (SELECT coalesce(sum(purchase._total_ht(c2.id)), 0) FROM purchase.commande c2
             WHERE c2.fournisseur_id = cl.id AND extract(year FROM c2.created_at) = v_annee
               AND extract(month FROM c2.created_at) = 12) AS m12
      FROM crm.client cl
     WHERE EXISTS (
       SELECT 1 FROM purchase.commande c3
        WHERE c3.fournisseur_id = cl.id
          AND extract(year FROM c3.created_at) = v_annee
     )
     ORDER BY cl.name
  LOOP
    DECLARE
      v_row_total numeric(12,2);
      v_months numeric[] := ARRAY[r.m01, r.m02, r.m03, r.m04, r.m05, r.m06,
                                   r.m07, r.m08, r.m09, r.m10, r.m11, r.m12];
    BEGIN
      v_row_total := r.m01 + r.m02 + r.m03 + r.m04 + r.m05 + r.m06
                   + r.m07 + r.m08 + r.m09 + r.m10 + r.m11 + r.m12;
      v_total_annuel := v_total_annuel + v_row_total;

      v_rows := v_rows || format('<a href="/crm/client?p_id=%s">%s</a>',
        r.fournisseur_id, pgv.esc(r.fournisseur));
      FOR i IN 1..12 LOOP
        v_rows := v_rows || CASE WHEN v_months[i] = 0 THEN '—'
          ELSE to_char(v_months[i], 'FM999 990') END;
      END LOOP;
      v_rows := v_rows || ('<strong>' || to_char(v_row_total, 'FM999 990') || '</strong>');
    END;
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty(pgv.t('purchase.empty_no_commande'));
  ELSE
    v_body := v_body || pgv.stat(pgv.t('purchase.stat_total_annuel'), to_char(v_total_annuel, 'FM999 990.00') || ' EUR');
    v_body := v_body || pgv.md_table(v_headers, v_rows);
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_recapitulatif(integer) IS 'Recapitulatif achats annuel — tableau croise fournisseur x mois avec totaux HT';

